const result = $input.first().json || {};
const requestedPlatforms = ['wanted', 'jobkorea', 'saramin'];
const thresholdMs = 2 * 60 * 60 * 1000;
const expiresAt = result.expiresAt || null;
const renewedAt = result.renewedAt || null;
const statusCode = result.statusCode || result.code || null;
const apiError = result.error || result.message || (statusCode && statusCode >= 400 ? `Session status request failed (${statusCode})` : null);
const valid = result.valid === true && !apiError;
const expiryTime = expiresAt ? new Date(expiresAt).getTime() : Number.NaN;
const nearExpiry = !apiError && Number.isFinite(expiryTime) ? expiryTime - Date.now() <= thresholdMs : false;
const needsRenewal = Boolean(apiError || !valid || nearExpiry);

return {
  requestedPlatforms,
  attemptedPlatforms: [...requestedPlatforms],
  platformsToRun: [...requestedPlatforms],
  skippedPlatforms: [],
  keywords: ['시니어 엔지니어', '클라우드 엔지니어', 'SRE', 'DevOps'],
  maxApplications: 10,
  dryRun: false,
  preflight: {
    wanted: {
      checked: true,
      valid,
      nearExpiry,
      needsRenewal,
      renewed: false,
      skipped: false,
      reason: apiError ? 'status_error' : (!valid ? 'invalid_session' : (nearExpiry ? 'near_expiry' : 'valid')),
      apiError,
      renewalError: null,
      expiresAt,
      renewedAt
    }
  }
};

const context = JSON.parse(JSON.stringify($('Evaluate Wanted Session').first().json));
const result = $input.first().json || {};
const statusCode = result.statusCode || result.code || null;
const renewalError = result.error || result.message || (statusCode && statusCode >= 400 ? `Session renewal request failed (${statusCode})` : null);
const renewedSession = result.session || {};
const renewed = result.success === true && renewedSession.valid === true && !renewalError;

context.preflight.wanted.renewed = renewed;
context.preflight.wanted.valid = renewed ? true : context.preflight.wanted.valid;
context.preflight.wanted.needsRenewal = false;
context.preflight.wanted.expiresAt = renewedSession.expiresAt || context.preflight.wanted.expiresAt;
context.preflight.wanted.renewedAt = renewedSession.renewedAt || context.preflight.wanted.renewedAt;

if (renewed) {
  context.preflight.wanted.reason = 'renewed';
  context.preflight.wanted.apiError = null;
  context.preflight.wanted.renewalError = null;
} else {
  const failureReason = renewalError || 'Wanted session renewal failed';
  context.platformsToRun = context.platformsToRun.filter((platform) => platform !== 'wanted');
  if (!context.skippedPlatforms.includes('wanted')) {
    context.skippedPlatforms.push('wanted');
  }
  context.preflight.wanted.skipped = true;
  context.preflight.wanted.valid = false;
  context.preflight.wanted.reason = 'renewal_failed';
  context.preflight.wanted.renewalError = failureReason;
}

return context;

const context = $input.first().json || {};
const requestBody = {
  dryRun: context.dryRun === true ? true : false,
  maxApplications: context.maxApplications || 10,
  platforms: context.platformsToRun || ['jobkorea', 'saramin'],
  keywords: context.keywords || []
};

return {
  ...context,
  requestBody
};

const status = $input.first().json || {};
const lastResult = status.lastResult || {};
const phases = lastResult.phases || {};
const requestContext = $('Build Auto-Apply Request').first().json || {};
const attemptedPlatforms = requestContext.attemptedPlatforms || [];
const executedPlatforms = requestContext.platformsToRun || [];
const skippedPlatforms = requestContext.skippedPlatforms || [];
const preflight = requestContext.preflight || {};
const searchCount = phases.search?.found || 0;
const filterMatched = phases.filter?.stats?.matched || phases.filter?.matched || 0;
const applied = phases.apply?.succeeded || 0;
const failed = phases.apply?.failed || 0;
const skipped = phases.apply?.skipped || 0;
const isSuccess = status.status === 'completed' && lastResult.success !== false;
const duration = status.lastRun ? Math.round((Date.now() - new Date(status.lastRun).getTime()) / 1000) : 0;
const statsLine = `Found ${searchCount} jobs, ${filterMatched} matched, ${applied} applied, ${failed} failed, ${skipped} skipped`;
const platformStats = lastResult?.results?.phase1_search?.platformStats || phases.search?.platformStats || phases.search?.sourceStats || {};
const successes = new Set();
const failures = new Set(skippedPlatforms);
const platforms = {};

for (const platform of attemptedPlatforms) {
  const skippedByPreflight = skippedPlatforms.includes(platform);
  const stat = platformStats[platform] || {};
  const ran = executedPlatforms.includes(platform) && !skippedByPreflight;
  let valid = false;

  if (skippedByPreflight) {
    valid = false;
  } else if (Object.keys(platformStats).length > 0) {
    valid = Boolean(
      stat.success === true ||
      stat.succeeded > 0 ||
      stat.applied > 0 ||
      stat.found > 0 ||
      stat.jobs > 0
    );
  } else {
    valid = isSuccess && ran;
  }

  if (valid) {
    successes.add(platform);
  } else if (ran || skippedByPreflight || status.status === 'failed') {
    failures.add(platform);
  }

  const reason = skippedByPreflight
    ? preflight.wanted?.renewalError || preflight.wanted?.apiError || preflight.wanted?.reason || 'skipped'
    : stat.error || (status.status === 'failed' && ran ? lastResult.error || status.lastError || 'platform_failed' : null);

  platforms[platform] = {
    attempted: attemptedPlatforms.includes(platform),
    valid,
    skipped: skippedByPreflight,
    reason,
    expiresAt: platform === 'wanted' ? preflight.wanted?.expiresAt || null : null,
    renewedAt: platform === 'wanted' ? preflight.wanted?.renewedAt || null : null
  };
}

const successPlatforms = Array.from(successes);
const failurePlatforms = Array.from(failures);
const reportPayload = {
  event: 'job-auto-apply-completed',
  timestamp: new Date().toISOString(),
  source: 'job-auto-apply',
  actions: {
    autoApply: true,
    sessionPrecheck: true,
    report: true
  },
  summary: {
    attempted: attemptedPlatforms,
    executed: executedPlatforms,
    skipped: skippedPlatforms,
    successes: successPlatforms,
    failures: failurePlatforms
  },
  platforms,
  result: {
    status: status.status,
    success: isSuccess,
    dryRun: Boolean(lastResult.dryRun),
    searchCount,
    filterMatched,
    applied,
    failed,
    skipped,
    error: lastResult.error || status.lastError || null
  }
};

return {
  isSuccess,
  status: status.status,
  channel: 'auto-apply',
  command: `auto-apply (${lastResult?.dryRun ? 'dry-run' : 'live'})`,
  duration,
  source: 'job-automation',
  errorMessage: isSuccess ? null : (lastResult.error || statsLine),
  outputUrl: null,
  pollCount: null,
  attemptedPlatforms,
  successPlatforms,
  failurePlatforms,
  reportPayload
};

// Track poll count to prevent infinite loops
const staticData = $getWorkflowStaticData('global');
staticData.pollCount = (staticData.pollCount || 0) + 1;

const MAX_POLLS = 40; // 40 polls * 30s = ~20 minutes max

if (staticData.pollCount >= MAX_POLLS) {
  const count = staticData.pollCount;
  staticData.pollCount = 0;
  return {
    isSuccess: false,
    status: 'timeout',
    channel: 'auto-apply',
    command: 'auto-apply',
    duration: count * 30,
    source: 'job-automation',
    timedOut: true,
    pollCount: count,
    errorMessage: `Auto-apply timed out after ${count} polls (~${Math.round(count * 30 / 60)} minutes)`
  };
}

return $input.first().json;

// Reset poll counter on completion
const staticData = $getWorkflowStaticData('global');
staticData.pollCount = 0;
return $input.first().json;

const payload = $input.first().json || {};
const requestContext = $('Build Auto-Apply Request').first().json || {};
const attemptedPlatforms = requestContext.attemptedPlatforms || [];
const executedPlatforms = requestContext.platformsToRun || [];
const skippedPlatforms = requestContext.skippedPlatforms || [];
const preflight = requestContext.preflight || {};
const failures = Array.from(new Set([...executedPlatforms, ...skippedPlatforms]));
const platforms = {};

for (const platform of attemptedPlatforms) {
  const skippedByPreflight = skippedPlatforms.includes(platform);
  platforms[platform] = {
    attempted: attemptedPlatforms.includes(platform),
    valid: false,
    skipped: skippedByPreflight,
    reason: skippedByPreflight
      ? preflight.wanted?.renewalError || preflight.wanted?.apiError || preflight.wanted?.reason || 'skipped'
      : payload.errorMessage || 'timeout',
    expiresAt: platform === 'wanted' ? preflight.wanted?.expiresAt || null : null,
    renewedAt: platform === 'wanted' ? preflight.wanted?.renewedAt || null : null
  };
}

return {
  ...payload,
  reportPayload: {
    event: 'job-auto-apply-timeout',
    timestamp: new Date().toISOString(),
    source: 'job-auto-apply',
    actions: {
      autoApply: true,
      sessionPrecheck: true,
      report: true
    },
    summary: {
      attempted: attemptedPlatforms,
      executed: executedPlatforms,
      skipped: skippedPlatforms,
      successes: [],
      failures
    },
    platforms,
    result: {
      status: 'timeout',
      success: false,
      error: payload.errorMessage || 'Auto-apply timed out'
    }
  }
};

const error = $input.first().json || {};
const requestContext = $('Build Auto-Apply Request').first().json || {};
const attemptedPlatforms = requestContext.attemptedPlatforms || [];
const executedPlatforms = requestContext.platformsToRun || [];
const skippedPlatforms = requestContext.skippedPlatforms || [];
const preflight = requestContext.preflight || {};
const platforms = {};

for (const platform of attemptedPlatforms) {
  const skippedByPreflight = skippedPlatforms.includes(platform);
  platforms[platform] = {
    attempted: attemptedPlatforms.includes(platform),
    valid: false,
    skipped: skippedByPreflight,
    reason: skippedByPreflight
      ? preflight.wanted?.renewalError || preflight.wanted?.apiError || preflight.wanted?.reason || 'skipped'
      : error.message || JSON.stringify(error).substring(0, 200),
    expiresAt: platform === 'wanted' ? preflight.wanted?.expiresAt || null : null,
    renewedAt: platform === 'wanted' ? preflight.wanted?.renewedAt || null : null
  };
}

return {
  isSuccess: false,
  status: 'error',
  channel: 'auto-apply',
  command: 'auto-apply',
  duration: 0,
  source: 'job-automation',
  errorMessage: error.message || JSON.stringify(error).substring(0, 500),
  reportPayload: {
    event: 'job-auto-apply-error',
    timestamp: new Date().toISOString(),
    source: 'job-auto-apply',
    actions: {
      autoApply: true,
      sessionPrecheck: true,
      report: true
    },
    summary: {
      attempted: attemptedPlatforms,
      executed: executedPlatforms,
      skipped: skippedPlatforms,
      successes: [],
      failures: Array.from(new Set([...executedPlatforms, ...skippedPlatforms]))
    },
    platforms,
    result: {
      status: 'error',
      success: false,
      error: error.message || JSON.stringify(error).substring(0, 500)
    }
  }
};
